// @mui
import { styled } from '@mui/material/styles';
// components
import Page from '../../components/Page';
// sections
import {Box,Typography,TextField} from "@mui/material"
import { borderRadius } from '@mui/system';
import { IconButtonAnimate, varFade } from '../../components/animate';
import Iconify from '../../components/Iconify';
import Footer from '../../components/onboarding/footer'
import {useNavigate} from "react-router"
import { useState } from 'react';
import {updateFeedback} from "../../redux/actions/feedback"
import { useDispatch,useSelector } from 'react-redux';
import { updateOnboarding } from '../../redux/actions/Onboarding';
import {useLocation} from "react-router"
import axios from "../../utils/axios";
import api from "../../utils/api";
// ----------------------------------------------------------------------
import Header from "../../components/onboarding/header"
import OtpInput from "react-otp-input";
const RootStyle = styled('div')(() => ({
  display:"flex",
  flexDirection:"column",
  flex:1,
  flexGrow:1,
  height:"100vh"
}));

const BoxStyle=styled(Box)(()=>({
position:"relative"
}))

const InsideBoxStyle=styled(Box)(()=>({
    position:"absolute",
    width:"100%",
    display:"flex",
    justifyContent:"center",
    alignItems:"center",
    flexDirection:"column",
    paddingTop:52,
    paddingBottom:24,
    zIndex:100,
    top:0,
    }))
    

// ----------------------------------------------------------------------

export default function HomePage() {
    const navigate=useNavigate()
    const dispatch=useDispatch()
    const Onboarding=useSelector(s=>s.Onboarding)
const {state} = useLocation();
    const [verificationCode, setCode] = useState("");
    const inputCode = (otp) => {
      const regexp = /^[0-9]*$/;
  
      let code = otp.toString();
      console.log(code);
      if (regexp.test(code)) {
        setCode(code);
      }
      if (code.length == 0) {
        setCode("");
      }
    };


    const handleVerification=()=>{
   

      axios
      .post(`${api.protocol}${api.baseUrl}${api.verifyMail}`, {
        email: Onboarding.email,
        token: verificationCode,
      })
      .then((res) => {
        dispatch(updateOnboarding({ token: res.data }));
        dispatch(updateFeedback({
          loading: false,
          snackbar: true,
          message: "Account verification completed",
          severity: "success",
        }))
        navigate(
          `/onboarding/info`,
          {state}
        );
      })
      .catch((err) => {
        if (err.response.status === 406)
        dispatch(updateFeedback({
            loading: false,
            snackbar: true,
            message: "Acccount with give email address already exists!",
            severity: "error",
          }))
        if (err.response.status === 404)
          return dispatch(updateFeedback({
            loading: false,
            snackbar: true,
            message: "Invalid code!",
            severity: "error",
          }))
      });
    }

    
  return (
    <Page title="The starting point for your next fitness gig">
      <RootStyle>
     < Header title={"Create new account"} />
       <Box display={"flex"} height={"100%"}  flexDirection={"column"} alignItems={"center"} flexGrow={1} px={2}>


     <Typography variant='h2'  sx={{my:6,mb:3}}>Verify email address</Typography>


     <Typography variant='"body2' color={"grey.600"}>Please enter the verification code sent to</Typography>
     <Typography variant='body2' color="primary"  sx={{my:1,fontWeight:"bold",mb:3}}>Aman@gmail.com</Typography>
     <Box width={"100%"}>
      
     <OtpInput
            value={verificationCode}
            onChange={inputCode}
            numInputs={6}
            isInputNum={true}
            shouldAutoFocus={true}
            separator={<span>&nbsp;</span>}
            containerStyle={{
              border: "none",
              width: "100%",
              justifyContent: "space-around",
            }}
            inputStyle={{
              borderTop: "none",
              borderLeft: "none",
              borderRight: "none",
              padding: 10,
              width:48,
              height:64,
              backgroundColor:"rgba(245, 247, 250, 1)",
              fontSize: 24,
              color: "#007ea0",
              boxShadow: "none",
              borderRadius: 8,
              borderBottom: "0px",
            }}
            focusStyle={{
              outline: "none",
              borderBottom: "0px",
              color: "#007ea0",
            }}
          />
     </Box>
     <Typography variant='"body2' sx={{my:3}} >Wait till 24s &nbsp;   <Typography sx={{fontWeight:"bold"}} variant='"body2' color="primary" >Resend code</Typography></Typography>
       </Box>
        <Footer back  next disabledNext={verificationCode.length<6} nextClick={handleVerification}/>
      </RootStyle>
    </Page>
  );
}
